// TODO: Remove file when webpack support is dropped
import type { Response } from 'express';
import type { ExtendedServerResponse } from 'webpack-dev-middleware';

import path from 'node:path';
import fs from 'node:fs';
import fsPromises from 'node:fs/promises';
import util from 'node:util';

import { getRes } from '@meli/server-context';
import { freezeObject } from '@nordic/utils/freeze';

type WebpackResponse = Response<
  unknown,
  NonNullable<NonNullable<ExtendedServerResponse>['locals']>
>;

function getWebpackDevFs() {
  return getRes<WebpackResponse>().locals.webpack?.devMiddleware
    ?.outputFileSystem;
}

export async function readBuildFileContent(fileName: string) {
  const filePath = path.resolve('build', fileName);
  const webpackDevFs = __DEV__ && getWebpackDevFs();
  const readFile = webpackDevFs
    ? util.promisify(webpackDevFs.readFile)
    : fsPromises.readFile;

  try {
    const content = await readFile(filePath, 'utf8');

    return content as string;
  } catch {
    return null;
  }
}

export function readBuildFileContentSync(fileName: string) {
  const filePath = path.resolve('build', fileName);
  const webpackDevFs = __DEV__ && getWebpackDevFs();

  try {
    const readFile = webpackDevFs ? webpackDevFs.readFileSync : fs.readFileSync;

    return readFile(filePath, 'utf8');
  } catch {
    return null;
  }
}

export function readLoadableStats() {
  try {
    return freezeObject(
      JSON.parse(fs.readFileSync('build/loadable-stats.json', 'utf8')),
    );
  } catch {
    return null;
  }
}
